import novamind_api as nm
import os, inspect
print('Module path:', nm.__file__)
print('Package dir:', os.path.dirname(nm.__file__))

# Search for log_rationale
def walk_mod(mod, prefix=''):
    found = []
    for name in dir(mod):
        if name.startswith('_'): continue
        obj = getattr(mod, name)
        if prefix:
            path = f'{prefix}.{name}'
        else:
            path = name
        if 'rationale' in str(name).lower() or 'log_rationale' in str(type(obj)).lower():
            found.append(path)
        if inspect.ismodule(obj):
            try:
                found.extend(walk_mod(obj, path))
            except Exception:
                pass
    return found

# Try all modules
for mod_name in dir(nm):
    if mod_name.startswith('_'): continue
    attr = getattr(nm, mod_name)
    if inspect.ismodule(attr):
        res = walk_mod(attr, mod_name)
        if res:
            print(f'Found rationale/log in {mod_name}:', res)

# Also try the client module
try:
    from novamind_api import _client
    print('Client methods:')
    for name in dir(_client):
        if 'rationale' in name.lower() or 'log' in name.lower():
            print(f'  _client.{name}')
except Exception as e:
    print('Client error:', e)
